/// Generate social auth setup instructions
fn generate_social_auth_setup(providers: &[SocialProviderConfig]) -> String {
    if providers.is_empty() {
        return "No social authentication providers enabled.".to_string();
    }

    let mut setup = vec!["Configure social authentication providers:".to_string(), "".to_string()];

    for provider in providers {
        let guide = match provider.name.as_str() {
            "google" => GOOGLE_SETUP_GUIDE,
            "github" => GITHUB_SETUP_GUIDE,
            "microsoft" => MICROSOFT_SETUP_GUIDE,
            "apple" => APPLE_SETUP_GUIDE,
            "facebook" => FACEBOOK_SETUP_GUIDE,
            "linkedin" => LINKEDIN_SETUP_GUIDE,
            "twitter" | "x" => TWITTER_SETUP_GUIDE,
            _ => "Provider setup guide not available.",
        };

        setup.push(format!("#### {}\n", provider.name.to_uppercase()));
        setup.push(guide.to_string());
        setup.push("".to_string());
    }

    setup.join("\n")
}

