#[cfg(test)]
mod tests {
    use super::*;
    use crate::config::auth_config::{AuthConfigGenerator, InstallMode};
    use crate::security::SecretsManager;

    #[test]
    fn test_django_settings_generation() {
        let mut secrets = SecretsManager::new();
        let config = AuthConfigGenerator::generate(InstallMode::Full, &mut secrets).unwrap();
        let settings = django_settings_toml(&config);

        assert!(settings.contains("SYNTEK_AUTH"));
        assert!(settings.contains("EMAIL_ENCRYPTION_KEY"));
        assert!(settings.contains("RATE_LIMITING"));
    }

    #[test]
    fn test_env_template_generation() {
        let mut secrets = SecretsManager::new();
        let config = AuthConfigGenerator::generate(InstallMode::Full, &mut secrets).unwrap();
        let env = env_template(&config);

        assert!(env.contains("EMAIL_ENCRYPTION_KEY"));
        assert!(env.contains("SECRET_KEY"));
    }

    #[test]
    fn test_readme_generation() {
        let mut secrets = SecretsManager::new();
        let config = AuthConfigGenerator::generate(InstallMode::Full, &mut secrets).unwrap();
        let readme = configuration_readme(&config);

        assert!(readme.contains("Configuration Files"));
        assert!(readme.contains("Setup Steps"));
    }
}
